// ================================================
// Dynamic blob path — har mahine auto update hoga
// Azure Export folder: YYYYMMDD-YYYYMMDD/{uuid}/parte_cont.csv
// ================================================
const now   = new Date();
const year  = now.getUTCFullYear();
const month = now.getUTCMonth();

const firstDay = new Date(Date.UTC(year, month, 1));
const lastDay  = new Date(Date.UTC(year, month + 1, 0));

const pad = n => String(n).padStart(2, '0');
const fmt = d => `${d.getUTCFullYear()}${pad(d.getUTCMonth()+1)}${pad(d.getUTCDate())}`;

const folderRange = `${fmt(firstDay)}-${fmt(lastDay)}`;

// Aapka Azure export UUID — agar export recreate karo toh yahan update karo
const EXPORT_UUID = '2647842c-fd21-4999-abta-a3ff4b3eb84f';

const blobPath = `finops/finops-export-daily-finopsexport/${folderRange}/${EXPORT_UUID}/parte_cont.csv`;

console.log(`[FinOps] Blob path: ${blobPath}`);
console.log(`[FinOps] Run date: ${now.toISOString()}`);

return [{
  json: { blobPath, folderRange, runDate: now.toISOString() }
}];

// ================================================
// Clean + Validate + Type cast
// ================================================
const items   = $input.all();
const cleaned = [];
let   skipped = 0;

for (const item of items) {
  const r = item.json;

  if (!r.SubscriptionGuid || !r.UsageDateTime) { skipped++; continue; }

  let usageDate = '';
  try {
    usageDate = new Date(r.UsageDateTime).toISOString().split('T')[0];
  } catch(e) {
    usageDate = String(r.UsageDateTime || '').split('T')[0].trim();
  }
  if (!usageDate || usageDate.startsWith('Invalid')) { skipped++; continue; }

  const safeNum    = v => { const n = parseFloat(String(v||'0').replace(/,/g,'').trim()); return isNaN(n) ? 0 : n; };
  const nullIfEmpty = v => { const s = String(v||'').trim(); return s==='' ? null : s; };

  cleaned.push({ json: {
    subscription_guid: String(r.SubscriptionGuid||'').trim().toLowerCase(),
    resource_group:    nullIfEmpty(r.ResourceGroup),
    resource_location: nullIfEmpty(r.ResourceLocation),
    usage_date:        usageDate,
    meter_category:    nullIfEmpty(r.MeterCategory),
    meter_id:          nullIfEmpty(r.MeterId),
    meter_name:        nullIfEmpty(r.MeterName),
    usage_quantity:    safeNum(r.UsageQuantity),
    resource_rate:     safeNum(r.ResourceRate),
    pre_tax_cost:      safeNum(r.PreTaxCost),
    consumed_service:  nullIfEmpty(r.ConsumedService),
    resource_type:     nullIfEmpty(r.ResourceType),
    instance_id:       nullIfEmpty(r.InstanceId),
    offer_id:          nullIfEmpty(r.OfferId),
    service_name:      nullIfEmpty(r.ServiceName),
    service_tier:      nullIfEmpty(r.ServiceTier),
    currency:          nullIfEmpty(r.Currency) || 'USD'
  }});
}

if (cleaned.length === 0) {
  throw new Error(`[FinOps] Koi valid row nahi mili. Total: ${items.length}, Skipped: ${skipped}`);
}
console.log(`[FinOps] Clean done — Valid: ${cleaned.length}, Skipped: ${skipped}`);
return cleaned;

// ================================================
// Sirf latest UsageDate ki rows rakho
// CSV mein poora month-to-date data hota hai
// ================================================
const items = $input.all();
if (items.length === 0) return [];

const latestDate = items.reduce((max, item) => {
  const d = item.json.usage_date || '';
  return d > max ? d : max;
}, '');

if (!latestDate) throw new Error('[FinOps] usage_date nahi mili');

const latest = items.filter(i => i.json.usage_date === latestDate);
console.log(`[FinOps] Latest date: ${latestDate} — ${latest.length} rows`);

return latest.map(i => ({ json: { ...i.json, _latestDate: latestDate } }));

// ================================================
// 500 rows ke batches banao — Supabase bulk limit
// ================================================
const items      = $('Filter Latest Date').all();
const BATCH_SIZE = 500;
const batches    = [];

for (let i = 0; i < items.length; i += BATCH_SIZE) {
  const batch = items.slice(i, i + BATCH_SIZE).map(item => {
    const row = { ...item.json };
    delete row._latestDate;
    return row;
  });
  batches.push({ json: {
    rows:         batch,
    batchNum:     Math.floor(i / BATCH_SIZE) + 1,
    totalBatches: Math.ceil(items.length / BATCH_SIZE),
    rowCount:     batch.length
  }});
}

console.log(`[FinOps] ${batches.length} batches, ${items.length} total rows ready`);
return batches;

const date      = $('Filter Latest Date').first().json._latestDate;
const totalRows = $('Filter Latest Date').all().length;
console.log(`[FinOps] SKIP — ${date} ka data (${totalRows} rows) already Supabase mein hai`);
return [{ json: { status: 'skipped', date, totalRows, reason: 'Already ingested' } }];
